## Semantic Version Parser
```python
import re
from dataclasses import dataclass

SEMVER_RE = re.compile(
    r"^(?P<major>\d+)\.(?P<minor>\d+)\.(?P<patch>\d+)(?:-(?P<prerelease>[0-9A-Za-z.-]+))?$"
)

@dataclass
class Version:
    major: int
    minor: int
    patch: int
    prerelease: str | None = None

def parse_version(text: str) -> Version:
    match = SEMVER_RE.match(text)
    if not match:
        raise ValueError("invalid semver")
    return Version(
        int(match.group("major")),
        int(match.group("minor")),
        int(match.group("patch")),
        match.group("prerelease"),
    )
```

## Markdown TOC Generator
```python
import re

HEADING_RE = re.compile(r"^(?P<level>#{1,6})\s+(?P<title>.+)$", re.MULTILINE)

def slugify(title: str) -> str:
    return re.sub(r"[^a-z0-9]+", "-", title.lower()).strip("-")

def build_toc(markdown: str) -> str:
    lines = ["# Table of Contents"]
    for match in HEADING_RE.finditer(markdown):
        level = len(match.group("level"))
        title = match.group("title").strip()
        indent = "  " * (level - 1)
        lines.append(f"{indent}- [{title}](#{slugify(title)})")
    return "\n".join(lines)
```

## Cache-Aside Pattern
```python
from typing import Callable, TypeVar

T = TypeVar("T")

class CacheAside:
    def __init__(self, cache: dict[str, T]) -> None:
        self.cache = cache

    def get_or_load(self, key: str, loader: Callable[[], T]) -> T:
        if key in self.cache:
            return self.cache[key]
        value = loader()
        self.cache[key] = value
        return value
```

## Circuit Breaker
```python
import time
from enum import Enum
from typing import Callable, TypeVar

T = TypeVar("T")

class State(Enum):
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 5, reset_timeout: float = 30.0) -> None:
        self.failure_threshold = failure_threshold
        self.reset_timeout = reset_timeout
        self.failures = 0
        self.state = State.CLOSED
        self.opened_at = 0.0

    def call(self, fn: Callable[[], T]) -> T:
        if self.state == State.OPEN:
            if time.monotonic() - self.opened_at >= self.reset_timeout:
                self.state = State.HALF_OPEN
            else:
                raise RuntimeError("circuit open")
        try:
            result = fn()
        except Exception:
            self.failures += 1
            if self.failures >= self.failure_threshold:
                self.state = State.OPEN
                self.opened_at = time.monotonic()
            raise
        self.failures = 0
        self.state = State.CLOSED
        return result
```

## Saga Orchestrator
```python
from dataclasses import dataclass
from typing import Callable

@dataclass
class SagaStep:
    name: str
    action: Callable[[], None]
    compensate: Callable[[], None]

class Saga:
    def __init__(self, steps: list[SagaStep]) -> None:
        self.steps = steps

    def run(self) -> None:
        completed: list[SagaStep] = []
        try:
            for step in self.steps:
                step.action()
                completed.append(step)
        except Exception:
            for step in reversed(completed):
                step.compensate()
            raise
```

## Safe Arithmetic Expression Evaluator
```python
import ast
import operator as op

OPS = {
    ast.Add: op.add,
    ast.Sub: op.sub,
    ast.Mult: op.mul,
    ast.Div: op.truediv,
    ast.Pow: op.pow,
    ast.USub: op.neg,
}

def eval_expr(expr: str) -> float:
    node = ast.parse(expr, mode="eval").body

    def _eval(n):
        if isinstance(n, ast.Num):
            return n.n
        if isinstance(n, ast.BinOp):
            return OPS[type(n.op)](_eval(n.left), _eval(n.right))
        if isinstance(n, ast.UnaryOp):
            return OPS[type(n.op)](_eval(n.operand))
        raise ValueError("unsupported expression")

    return float(_eval(node))
```

